        /// <summary>
        /// 加载设置
        /// </summary>
        private void LoadSettings()
        {
            try
            {
                if (!File.Exists(SettingsFilePath))
                {
                    // 首次运行，设置默认分块大小等（已在控件的默认值中设置）
                    return;
                }

                var serializer = new XmlSerializer(typeof(AppSettings));
                AppSettings settings;
                using (var reader = new StreamReader(SettingsFilePath, Encoding.UTF8))
                {
                    settings = (AppSettings)serializer.Deserialize(reader);
                }

                if (settings == null) return;

                // 目标目录
                textBox2.Text = settings.TargetDirectory ?? "";

                // 文件类型
                checkBox1.Checked = settings.CopyPpt;
                checkBox2.Checked = settings.CopyWord;
                checkBox3.Checked = settings.CopyExcel;
                checkBox4.Checked = settings.CopyPdf;
                checkBox5.Checked = settings.CopyImage;
                checkBox6.Checked = settings.CopyVideo;
                checkBox10.Checked = settings.CopyAudio;
                checkBox9.Checked = settings.CopyCompressed;
                checkBox8.Checked = settings.CopyAllFiles;
                checkBox7.Checked = settings.UseCustomExtensions;
                textBox1.Text = settings.CustomExtensions ?? "";

                // 重复文件处理
                switch (settings.DuplicateFileAction)
                {
                    case 0: radioButton1.Checked = true; break;
                    case 1: radioButton2.Checked = true; break;
                    case 2: radioButton3.Checked = true; break;
                    case 3: radioButton4.Checked = true; break;
                }

                // 文件大小限制
                checkBox11.Checked = settings.EnableFileSizeLimit;
                textBox3.Text = settings.MaxFileSizeMB.ToString();

                // 文件名过滤
                checkBox12.Checked = settings.EnableFileNameFilter;
                textBox4.Text = settings.FileNameKeywords ?? "";

                // 文件夹过滤
                checkBox21.Checked = settings.EnableFolderNameFilter;
                textBox7.Text = settings.FolderNameKeywords ?? "";

                // 目录深度
                checkBox22.Checked = settings.CreateDirectoryTree;
                checkBox23.Checked = settings.LimitDirectoryDepth;
                numericUpDown2.Value = settings.MaxDirectoryDepth;

                // 日志设置
                checkBox16.Checked = settings.LogSuccess;
                checkBox17.Checked = settings.LogErrors;
                checkBox18.Checked = settings.LogNeutral;
                checkBox19.Checked = settings.SaveLogToFile;
                checkBox20.Checked = settings.ShowLogInWindow;

                // USB特殊文件
                checkBox14.Checked = settings.EnableStopCopyFile;
                textBox5.Text = settings.StopCopyFileName;
                checkBox15.Checked = settings.EnableReverseCopyFile;
                textBox6.Text = settings.ReverseCopyFileName;

                // 速度限制
                checkBox13.Checked = settings.EnableSpeedLimit;
                numericUpDown1.Value = settings.SpeedLimitMinutes;
                comboBoxSpeed.SelectedIndex = settings.SpeedLimitIndex >= 0 ? settings.SpeedLimitIndex : 1;

                // 开机自启动
                checkBox24.Checked = settings.AutoStart;
                checkBox25.Checked = settings.AutoStartHidden;

                // ===== 新增：服务器相关 =====
                if (settings.Server != null)
                {
                    textBox8.Text = settings.Server.ServerAddress ?? "";
                    if (textBox11 != null) textBox11.Text = settings.Server.Port.ToString();
                    if (checkBox26 != null) checkBox26.Checked = settings.Server.UseHttps;
                    textBox9.Text = DecryptString(settings.Server.Password);
                    textBox10.Text = DecryptString(settings.Server.ApiToken);
                    // 分块大小恢复（需要将字节转换为 KB/MB）
                    RestoreChunkSizeUI(settings.Server.ChunkSizeBytes);
                }

                // 保存位置
                if (settings.SaveLocation == 0)
                    radioButton5.Checked = true;
                else
                    radioButton6.Checked = true;

                // 同步内部字段
                ApplySettingsToFields(settings);
            }
            catch (Exception ex)
            {
                LogMessage($"加载设置失败: {ex.Message}", true);
            }
        }

        // ===== 加密辅助方法 =====
        private static string EncryptString(string plainText)
        {
            if (string.IsNullOrEmpty(plainText)) return "";
            byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
            byte[] encryptedBytes = ProtectedData.Protect(plainBytes, Entropy, DataProtectionScope.CurrentUser);
            return Convert.ToBase64String(encryptedBytes);
        }

        private static string DecryptString(string encryptedBase64)
        {
            if (string.IsNullOrEmpty(encryptedBase64)) return "";
            byte[] encryptedBytes = Convert.FromBase64String(encryptedBase64);
            byte[] plainBytes = ProtectedData.Unprotect(encryptedBytes, Entropy, DataProtectionScope.CurrentUser);
            return Encoding.UTF8.GetString(plainBytes);
        }

        // ===== 分块大小序列化辅助 =====
        private int ParseChunkSize()
        {
            if (!int.TryParse(textBox12?.Text, out int val) || val <= 0) val = 1;
            string unit = comboBox1?.SelectedItem?.ToString() ?? "MB";
            if (unit == "MB")
                return val * 1024 * 1024;
            else
                return val * 1024;
        }

        private void RestoreChunkSizeUI(int chunkSizeBytes)
        {
            if (textBox12 == null || comboBox1 == null) return;
            if (chunkSizeBytes >= 1024 * 1024)
            {
                textBox12.Text = (chunkSizeBytes / (1024 * 1024)).ToString();
                comboBox1.SelectedItem = "MB";
            }
            else
            {
                textBox12.Text = (chunkSizeBytes / 1024).ToString();
                comboBox1.SelectedItem = "KB";
            }
        }

        private void ApplySettingsToFields(AppSettings settings)
