            _createDirectoryTree = settings.CreateDirectoryTree;
            _maxDirectoryDepth = settings.LimitDirectoryDepth ? settings.MaxDirectoryDepth : int.MaxValue;
            _logSuccess = settings.LogSuccess;
            _logErrors = settings.LogErrors;
            _logNeutral = settings.LogNeutral;
            _saveLogToFile = settings.SaveLogToFile;
            _showLogInWindow = settings.ShowLogInWindow;
            _stopCopyWhenFileExists = settings.EnableStopCopyFile;
            _reverseCopyWhenFileExists = settings.EnableReverseCopyFile;
            _stopCopyFileName = settings.StopCopyFileName;
            _reverseCopyFileName = settings.ReverseCopyFileName;
            _filterByFolderName = settings.EnableFolderNameFilter;
        }
